352		private getDayOfYear(date: Date): number {
353			const startOfYear = new Date(date.getFullYear(), 0, 1);
354			const diffInMs = date.getTime() - startOfYear.getTime();
355			const dayOfYear = Math.floor(diffInMs / (1000 * 60 * 60 * 24)) + 1;
356			return dayOfYear;
357		}
358	
359		private isLeapDay(date: Date): boolean {
360			return date.getMonth() === 1 && date.getDate() === 29;
361		}
362	
363		private isLeapYear(year: number): boolean {
364			return (year % 4 === 0 && year % 100 !== 0) || year % 400 === 0;
365		}
366	
367		private getAdjustedDayIndex(date: Date): number {
368			const dayOfYear = this.getDayOfYear(date);
369			const year = date.getFullYear();
370			const isAfterFeb =
371				date.getMonth() > 1 || (date.getMonth() === 1 && date.getDate() > 28);
372	
373			if (this.isLeapYear(year) && isAfterFeb) {
374				return dayOfYear - 2;
375			}
376	
377			return dayOfYear - 1;
378		}
379	
380		private extractCategoryFromOrders(
381			orderData: TrendingItemOrderDataDto[],
382			styleId: number,
383		): string | null {
384			const styleOrder = orderData.find((order) => order.style_id === styleId);
385			const category = styleOrder?.style_uber_category_name ?? null;
386			return category === '' ? null : category;
387		}
388	
389		private isForeignKeyConstraintError(error: unknown): boolean {
390			const dbError = error as { errno?: number; code?: string; message?: string };
391	
392			return (
393				dbError.errno === MYSQL_ERROR_CODE_FOREIGN_KEY_ERRNO ||
394				dbError.code === MYSQL_ERROR_CODE_FOREIGN_KEY_CODE
395			);
396		}
397	
398		private groupOrderDataByYear(
399			orderData: TrendingItemOrderDataDto[],
400		): Record<string, TrendingItemOrderDataDto[]> {
401			const groupedData: Record<string, TrendingItemOrderDataDto[]> = {};
402	
403			orderData.forEach((order) => {
404				if (!order.date_placed) return;
405	
406				const orderDate = new Date(order.date_placed);
407				const year = orderDate.getFullYear().toString();
408	
409				groupedData[year] ??= [];
410	
411				groupedData[year].push(order);
412			});
413	
414			return groupedData;
415		}
416	
417		private async updateExistingRecords(data: IProductAnnualSalesBase[]): Promise<void> {
418			for (const record of data) {
419				if (this.isCancelled) {
420					this.logger.warn('Update operation cancelled');
421					break;
422				}
423	
424				const styleExists: unknown = await this.knexWrite(TABLE_NAME_STYLES)
425					.where('style_id', record.style_id)
426					.first();
427	
428				if (!styleExists) {
429					this.logger.warn('Skipping record - style_id does not exist in styles table', {
430						styleId: record.style_id,
431					});
432					continue;
433				}
434	
435				try {
436					const existing: unknown = await this.knexWrite(TABLE_NAME_PRODUCT_ANNUAL_SALES)
437						.where('style_id', record.style_id)
438						.where('year', record.year)
439						.first();
440	
441					if (existing) {
442						const existingRecord = existing as IProductAnnualSalesBase;
443						const existingDailyOrders = Array.isArray(existingRecord.daily_orders)
444							? existingRecord.daily_orders
445							: (JSON.parse(
446									(existingRecord.daily_orders as unknown as string) || '[]',
447								) as number[]);
448	
449						const mergedDailyOrders = [...existingDailyOrders];
450						record.daily_orders.forEach((value, index) => {
451							if (value > 0) {
452								mergedDailyOrders[index] = value;
453							}
454						});
455	
456						await this.knexWrite(TABLE_NAME_PRODUCT_ANNUAL_SALES)
457							.where('style_id', record.style_id)
458							.where('year', record.year)
459							.update({
460								daily_orders: JSON.stringify(mergedDailyOrders),
461								is_holiday: JSON.stringify(record.is_holiday),
462								holiday_names: JSON.stringify(record.holiday_names),
463								holiday_multipliers: JSON.stringify(record.holiday_multipliers),
464								category: record.category,
465								updated_at: new Date(),
466							});
467						this.logger.debug('Updated existing record', {
468							styleId: record.style_id,
469							year: record.year,
470						});
471					} else {
472						await this.knexWrite(TABLE_NAME_PRODUCT_ANNUAL_SALES).insert({
473							_id: record._id,
474							style_id: record.style_id,
475							year: record.year,
476							daily_orders: JSON.stringify(record.daily_orders),
477							is_holiday: JSON.stringify(record.is_holiday),
478							holiday_names: JSON.stringify(record.holiday_names),
479							holiday_multipliers: JSON.stringify(record.holiday_multipliers),
480							category: record.category,
481							created_at: record.created_at,
482							updated_at: record.updated_at,
483						});
484						this.logger.debug('Inserted new record', {
485							styleId: record.style_id,
486							year: record.year,
487						});
488					}
489				} catch (error) {
490					if (this.isForeignKeyConstraintError(error)) {
491						this.logger.warn('Skipping style_id due to foreign key constraint', {
492							styleId: record.style_id,
493						});
494						continue;
495					}
496					this.logger.error(
497						`Failed to update existing records: ${(error as Error).message}`,
498						(error as Error).stack,
499					);
500					throw error;
501				}
502			}
503		}
504	
505		public cancelOperation(): void {
506			this.logger.warn('Cancelling current operation...');
507			this.isCancelled = true;
508		}
509	
510		public resetCancellation(): void {
511			this.isCancelled = false;
512		}
513	}
